import socket

# Scan potential docker bridge IPs for RocketChat and GitLab
print("Scanning for services...")
found = []

# Try common Docker network ranges
for prefix in ['172.17.0', '172.18.0', '172.19.0', '10.0.0', '192.168.0']:
    for i in range(1, 50):
        ip = f'{prefix}.{i}'
        for port, svc in [(3000, 'RocketChat'), (8929, 'GitLab')]:
            try:
                sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                sock.settimeout(0.2)
                result = sock.connect_ex((ip, port))
                if result == 0:
                    print(f'FOUND: {svc} at {ip}:{port}')
                    found.append((ip, port, svc))
                sock.close()
            except Exception as e:
                pass

if not found:
    print("No services found in scanned range")
else:
    print(f"Found {len(found)} service(s)")
EOF

