# Try one more extensive network scan including the gateway networks
python3 << 'EOF'
import socket
import concurrent.futures

def scan_port(args):
    ip, port = args
    try:
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(0.2)
        result = sock.connect_ex((ip, port))
        sock.close()
        if result == 0:
            return (ip, port)
    except:
        pass
    return None

# Networks to try
networks = [
    '172.17.0',  # Docker default bridge
    '172.18.0',  # Additional docker network
    '10.0.0',    # GCP internal
]

ports = [3000, 8929, 80, 443, 2999]

scan_targets = []
for net in networks:
    for i in range(1, 50):
        for port in ports:
            scan_targets.append((f'{net}.{i}', port))

print(f"Scanning {len(scan_targets)} targets...")

with concurrent.futures.ThreadPoolExecutor(max_workers=100) as executor:
    results = executor.map(scan_port, scan_targets)

for r in results:
    if r:
        print(f"FOUND: {r[0]}:{r[1]}")

print("Scan complete")
EOF

